@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }

    [Parameter] public int TimeoutSeconds { get; set; } = 300;

    [Parameter] public EventCallback OnIdle { get; set; }

    [Parameter] public EventCallback OnActive { get; set; }

    private ElementReference _element;
    private IJSObjectReference? _module;
    private DotNetObjectReference<UserActivityTracker>? _dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-5c87ebac36494addad1a9ec4785fba82/Components/UserActivityTracker.razor.js");
            await _module.InvokeVoidAsync("init", _element, _dotNetRef, TimeoutSeconds * 1000);
        }
    }

    [JSInvokable]
    public async Task OnIdleCallback()
    {
        await OnIdle.InvokeAsync();
    }

    [JSInvokable]
    public async Task OnActiveCallback()
    {
        await OnActive.InvokeAsync();
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try
            {
                await _module.InvokeVoidAsync("dispose");
                await _module.DisposeAsync();
            }
            catch (JSDisconnectedException)
            {
                // Circuit already closed — nothing to clean up on the JS side.
            }
        }

        _dotNetRef?.Dispose();
    }
}

let timer = null;
let dotNetHelper = null;
let isIdle = false;
let timeoutMs = 300000;
let registeredElement = null;

const events = ["mousemove", "keydown", "click", "scroll"];

function onActivity() {
    if (isIdle) {
        isIdle = false;
        dotNetHelper.invokeMethodAsync("OnActiveCallback");
    }
    resetTimer();
}

function resetTimer() {
    clearTimeout(timer);
    timer = setTimeout(() => {
        isIdle = true;
        dotNetHelper.invokeMethodAsync("OnIdleCallback");
    }, timeoutMs);
}

export function init(element, helper, timeout) {
    registeredElement = element;
    dotNetHelper = helper;
    timeoutMs = timeout;
    isIdle = false;

    events.forEach(e => element.addEventListener(e, onActivity, { passive: true }));
    resetTimer();
}

export function dispose() {
    clearTimeout(timer);
    timer = null;

    if (registeredElement) {
        events.forEach(e => registeredElement.removeEventListener(e, onActivity));
        registeredElement = null;
    }

    dotNetHelper = null;
    isIdle = false;
}

